components.codeTemplate:
.alert(${title}, isPresented: ${isPresented}) {
    Button("Confirm", role: ${primaryButtonRole}) { confirm() }
    Button("Cancel", role: .cancel) { }
} message: {
    Text(${message})
}

.confirmationDialog(${title}, isPresented: ${isPresented}, titleVisibility: ${titleVisibility}) {
    Button("Delete", role: .destructive) { delete() }
    Button("Cancel", role: .cancel) { }
} message: {
    Text(${message})
}

.fileImporter(
    isPresented: ${isPresented},
    allowedContentTypes: [${allowedContentTypes}],
    allowsMultipleSelection: ${allowsMultipleSelection}
) { result in
    switch result {
    case .success(let urls): handleImport(urls)
    case .failure(let error): handleError(error)
    }
}

.fileExporter(
    isPresented: ${isPresented},
    document: document,
    contentType: ${contentType},
    defaultFilename: ${defaultFilename}
) { result in
    if case .failure(let error) = result { handleError(error) }
}
.fileExporterFilenameLabel(${filenameLabel})

.fileMover(isPresented: ${isPresented}, file: ${file}) { result in
    switch result {
    case .success(let url): handleMoved(url)
    case .failure(let error): handleError(error)
    }
}

PhotosPicker(
    selection: ${selection},
    matching: ${matching},
    preferredItemEncoding: ${preferredItemEncoding},
    photoLibrary: ${photoLibrary}
) {
    Label("Select Photo", systemImage: "photo")
}
.photosPickerStyle(${style})

ShareLink(
    item: ${item},
    subject: ${subject},
    message: ${message},
    preview: SharePreview("Title", image: Image("thumb"))
) {
    Label("Share", systemImage: "square.and.arrow.up")
}

@Environment(\.dismiss) private var dismiss

var body: some View {
    Button("Done") { dismiss() }
}

SomeControl()
    .popoverTip(${tip}, arrowEdge: ${arrowEdge}) { action in
        // handle tip button actions
    }

Text(${text})
    .translationPresentation(
        isPresented: ${isPresented},
        text: ${text},
        attachmentAnchor: ${attachmentAnchor},
        arrowEdge: ${arrowEdge}
    ) { translated in
        // replace original text with translated
    }
